int main() {
    // Original string from which a substring will be extracted
    char original[] = "Programming";

    // Array to store the substring (5 characters + null terminator)
    char substring[6];

    int start = 3;    // Start from the 4th character ('g')
    int length = 5;   // Copy 5 characters

    // Extract substring using loop
    for (int i = 0; i < length; i++) {
        substring[i] = original[start + i];
    }
    substring[length] = '\0';  // Add null terminator

    // Print the extracted substring
    printf("Extracted Substring: %s\n", substring);  // Output: gramm

    return 0;
}
```

---

It gives you control over where to start and how many characters to include, and is helpful when working with character arrays in a low-level way.

